import type { ExpenseDeclarationDto, ExpenseDeclarationPeriodType } from '../../../services/master/models';

export const PERIOD_TYPE_OPTIONS: { value: ExpenseDeclarationPeriodType; label: string }[] = [
  { value: 'Month', label: 'Theo tháng' },
  { value: 'Year', label: 'Theo năm' },
  { value: 'Day', label: 'Theo ngày' },
];

export const PERIOD_TYPE_LABEL: Record<ExpenseDeclarationPeriodType, string> = {
  Day: 'Ngày',
  Month: 'Tháng',
  Year: 'Năm',
};

export type DeclFormState = {
  periodType: ExpenseDeclarationPeriodType;
  periodYear: string;
  monthYear: string;
  periodDate: string;
  expenseItemId: string;
  amount: number;
  description: string;
  showOnRevenueReport: boolean;
};

export type DeclFormErrors = Partial<Record<'periodYear' | 'monthYear' | 'periodDate' | 'expenseItemId' | 'amount', string>>;

export const emptyDeclForm = (filterMonthYear: string, filterDate: string): DeclFormState => ({
  periodType: 'Month',
  periodYear: filterMonthYear.slice(0, 4),
  monthYear: filterMonthYear,
  periodDate: filterDate,
  expenseItemId: '',
  amount: 0,
  description: '',
  showOnRevenueReport: false,
});

export function formatDeclPeriod(row: ExpenseDeclarationDto): string {
  const type = row.periodType ?? 'Month';
  if (type === 'Year') return String(row.year);
  if (type === 'Day' && row.day && row.month) return `${row.day}/${row.month}/${row.year}`;
  if (row.month) return `${row.month}/${row.year}`;
  return String(row.year);
}

export function declFormToCreatePayload(form: DeclFormState) {
  const base = {
    expenseItemId: form.expenseItemId,
    periodType: form.periodType,
    amount: form.amount,
    description: form.description.trim() || undefined,
    showOnRevenueReport: form.showOnRevenueReport,
  };
  if (form.periodType === 'Year') {
    return { ...base, year: Number(form.periodYear), month: null, day: null };
  }
  if (form.periodType === 'Month') {
    const [yearStr, monthStr] = form.monthYear.split('-');
    return { ...base, year: Number(yearStr), month: Number(monthStr), day: null };
  }
  const [yearStr, monthStr, dayStr] = form.periodDate.split('-');
  return { ...base, year: Number(yearStr), month: Number(monthStr), day: Number(dayStr) };
}

export function declRowToForm(row: ExpenseDeclarationDto): DeclFormState {
  const periodType = row.periodType ?? 'Month';
  const monthYear = row.month
    ? `${row.year}-${String(row.month).padStart(2, '0')}`
    : `${row.year}-01`;
  const periodDate = row.day && row.month
    ? `${row.year}-${String(row.month).padStart(2, '0')}-${String(row.day).padStart(2, '0')}`
    : new Date().toISOString().slice(0, 10);
  return {
    periodType,
    periodYear: String(row.year),
    monthYear,
    periodDate,
    expenseItemId: row.expenseItemId,
    amount: row.amount ?? 0,
    description: row.description ?? '',
    showOnRevenueReport: row.showOnRevenueReport ?? false,
  };
}

export function validateDeclForm(form: DeclFormState): DeclFormErrors {
  const next: DeclFormErrors = {};
  if (!form.expenseItemId) next.expenseItemId = 'Chọn khoản chi phí';
  if (!form.amount || form.amount <= 0) next.amount = 'Nhập chi phí dự kiến';
  if (form.periodType === 'Year') {
    if (!form.periodYear?.trim() || Number(form.periodYear) < 1900) next.periodYear = 'Chọn năm';
  } else if (form.periodType === 'Month') {
    if (!form.monthYear?.trim()) next.monthYear = 'Chọn tháng/năm';
  } else if (!form.periodDate?.trim()) {
    next.periodDate = 'Chọn ngày';
  }
  return next;
}
